const scrollData = $input.first().json;
const qdrantUrl = 'http://qdrant:6333';
const geminiKey = $env.GEMINI_API_KEY || '';

// Get all recent articles from scroll result
const recentArticles = scrollData.result?.points?.map(p => p.payload) || [];

// Embed search query for similarity search
let similarArticles = [];
try {
  const embData = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key=${geminiKey}`,
    body: {
      model: 'models/gemini-embedding-001',
      content: { parts: [{ text: 'Najważniejsze wydarzenia w powiecie kraśnickim: rada powiatu, BIP, inwestycje, sport, edukacja, bezpieczeństwo, przetargi' }] },
      outputDimensionality: 768
    },
    json: true
  });
  const embResult = embData;

  if (embResult.embedding?.values) {
    const searchData = await this.helpers.httpRequest({
      method: 'POST',
      url: `${qdrantUrl}/collections/krasnik_news/points/search`,
      body: {
        vector: embResult.embedding.values,
        limit: 20,
        with_payload: true,
        score_threshold: 0.3
      },
      json: true
    });
    const searchResult = searchData;
    similarArticles = searchResult.result?.map(r => ({ ...r.payload, score: r.score })) || [];
  }
} catch (e) {
  console.log('RAG search error:', e.message);
}

// Get yesterday's briefing for context (avoid repetition)
let yesterdayBriefing = '';
try {
  const briefData = await this.helpers.httpRequest({
    method: 'POST',
    url: `${qdrantUrl}/collections/krasnik_news/points/scroll`,
    body: {
      limit: 1,
      with_payload: true,
      with_vector: false,
      filter: {
        must: [{ key: 'category', match: { value: 'briefing' } }]
      },
      order_by: { key: 'date', direction: 'desc' }
    },
    json: true
  });
  const briefResult = briefData;
  yesterdayBriefing = briefResult.result?.points?.[0]?.payload?.description || '';
} catch (e) {
  console.log('Yesterday briefing fetch error:', e.message);
}

// Merge and deduplicate by URL
const allArticles = new Map();
for (const a of [...recentArticles, ...similarArticles]) {
  const key = a.url || a.title;
  if (!allArticles.has(key)) {
    allArticles.set(key, a);
  }
}

const articles = Array.from(allArticles.values())
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, 30);

const today = new Date().toLocaleDateString('pl-PL', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' 
});

// 4+5. Fetch preferences + style feedback (parallel)
let prefSummary = '';
let styleFeedback = '';
const qdrantScroll = (cat, lim) => this.helpers.httpRequest({
  method: 'POST', url: qdrantUrl + '/collections/krasnik_news/points/scroll',
  body: { limit: lim, with_payload: true, with_vector: false,
    filter: { must: [{ key: 'category', match: { value: cat } }] } },
  json: true
}).catch(e => { console.log('Qdrant scroll error (' + cat + '):', e.message); return { result: { points: [] } }; });

try {
  const [prefData, fbData] = await Promise.all([
    qdrantScroll('marcin-preference', 50),
    qdrantScroll('marcin-style-feedback', 10)
  ]);

  const prefs = (prefData.result?.points || []).map(p => p.payload);
  if (prefs.length > 0) {
    const topicCounts = {};
    for (const pref of prefs) {
      for (const t of (pref.topics || [])) topicCounts[t] = (topicCounts[t] || 0) + 1;
    }
    const sorted = Object.entries(topicCounts).sort((a, b) => b[1] - a[1]);
    if (sorted.length > 0) {
      prefSummary = 'Marcin najczesciej wybiera: ' + sorted.slice(0, 5).map(([t, c]) => t + ' (' + c + 'x)').join(', ');
    }
  }

  const feedbacks = (fbData.result?.points || []).map(p => p.payload?.feedback || p.payload?.feedback_text).filter(Boolean);
  if (feedbacks.length > 0) {
    styleFeedback = 'Feedback Marcina na temat stylu: ' + feedbacks.slice(0, 5).join('; ');
  }
} catch (e) { console.log('Pref/style fetch error:', e.message); }

return [{
  json: {
    articles,
    article_count: articles.length,
    preferences: prefSummary,
    style_feedback: styleFeedback,
    date: today,
    date_iso: new Date().toISOString(),
    yesterday_briefing: yesterdayBriefing.substring(0, 1000),
    sources: [...new Set(articles.map(a => a.source))].join(', ')
  }
}];

const ragData = $('RAG: Wyszukaj Istotne').first().json;
const aiResponse = $input.first().json.response || $input.first().json.text || '';
const articles = ragData.articles || [];
const dateIso = new Date().toISOString();
const qdrantUrl = 'http://qdrant:6333';
const geminiKey = $env.GEMINI_API_KEY || '';

// SHARED: simpleHash+makeUUID — keep identical across all Code nodes that use it
function simpleHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507);
  h1 ^= Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507);
  h2 ^= Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0') + '0000000000000000';
}
function makeUUID(input) {
  const h = simpleHash(input);
  return h.slice(0,8)+'-'+h.slice(8,12)+'-'+h.slice(12,16)+'-'+h.slice(16,20)+'-'+h.slice(20,32);
}

// Create numbered article list for interactive selection
let numberedList = '';
const indexArticles = [];
let num = 1;

for (const a of articles) {
  if (a.title && a.url) {
    numberedList += num + '. ' + a.title + '\n   ' + a.url + '\n';
    indexArticles.push({
      num: num,
      title: a.title,
      url: a.url,
      source: a.source || '',
      description: a.description || ''
    });
    num++;
  }
}

// Store briefing-index in Qdrant for FB Post Generator
// Use simple hash for UUID

try {
  // Embed a simple text to get vector for the index entry
  const embData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key=' + geminiKey,
    body: {
      model: 'models/gemini-embedding-001',
      content: { parts: [{ text: 'briefing index ' + dateIso }] },
      outputDimensionality: 768
    },
    json: true
  });
  const embResult = embData;

  if (embResult.embedding?.values) {
    const uuid = makeUUID('briefing-index-' + dateIso.substring(0, 10));

    // Delete previous briefing-index entries first
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: qdrantUrl + '/collections/krasnik_news/points/delete',
            body: {
          filter: { must: [{ key: 'category', match: { value: 'briefing-index' } }] }
        },
        json: true
      });
    } catch (e) { console.log('Delete briefing-index error:', e.message); }

    // Store new index
    await this.helpers.httpRequest({
      method: 'PUT',
      url: qdrantUrl + '/collections/krasnik_news/points',
        body: {
        points: [{
          id: uuid,
          vector: embResult.embedding.values,
          payload: {
            title: 'Briefing Index ' + new Date().toLocaleDateString('pl-PL'),
            url: '',
            description: 'Index of numbered articles for FB Post Generator',
            source: 'Radar Radnego',
            date: dateIso,
            category: 'briefing-index',
            articles_json: JSON.stringify(indexArticles)
          }
        }]
      }),
      json: true
    });
  }
} catch (e) {
  // Index storage failed - non-critical
}

// Build WhatsApp message with AI briefing + numbered list
const interactiveMsg = aiResponse;

// Truncate for Telegram (4096 char limit)
let telegramText = aiResponse;
if (telegramText.length > 4000) {
  telegramText = telegramText.substring(0, 3950) + '\n\n... Briefing skrocony (pelna wersja na WhatsApp)';
}

const smsText = 'Briefing Radnego gotowy! Sprawdz WhatsApp. ' + aiResponse.substring(0, 80) + '...';

return [{
  json: {
    briefing_full: aiResponse,
    briefing_telegram: telegramText,
    briefing_whatsapp: interactiveMsg,
    briefing_sms: smsText,
    date_iso: dateIso,
    date_pl: new Date().toLocaleDateString('pl-PL'),
    article_count: indexArticles.length
  }
}];

